	const fromMsg = (msg?.sendMemberName || msg?.sendNickName || msg?.sendRemarkName || "").toString().trim();
	const uin = res?.sender?.user_id ?? (msg?.senderUin != null ? Number(msg.senderUin) || msg.senderUin : 0);
