var SendPrivateMessage = defineApi("send_private_message", SendPrivateMessageInput, SendPrivateMessageOutput, async (ctx, payload) => {
	const uid = await ctx.ntUserApi.getUidByUin(payload.user_id.toString());
	if (!uid) return Failed(-404, "User not found");
	const peer = {
		chatType: 1,
		peerUid: uid,
		guildId: ""
	};
	if (!await ctx.ntFriendApi.isFriend(uid)) {
		if ((await ctx.ntMsgApi.getTempChatInfo(100, uid)).tmpChatInfo.groupCode) peer.chatType = 100;
	}
	const { elements, deleteAfterSentFiles } = await transformOutgoingMessage(ctx, payload.message, uid, false);
	const result = await ctx.app.sendMessage(ctx, peer, elements, deleteAfterSentFiles);
	return Ok({
		message_seq: +result.msgSeq,
		time: +result.msgTime
	});
});
var SendGroupMessage = defineApi("send_group_message", SendGroupMessageInput, SendGroupMessageOutput, async (ctx, payload) => {
	const groupCode = payload.group_id.toString();
	const peer = {
		chatType: 2,
		peerUid: groupCode,
		guildId: ""
	};
	const { elements, deleteAfterSentFiles } = await transformOutgoingMessage(ctx, payload.message, groupCode, true);
	const result = await ctx.app.sendMessage(ctx, peer, elements, deleteAfterSentFiles);
	return Ok({
		message_seq: +result.msgSeq,
		time: +result.msgTime
	});
});
var RecallPrivateMessage = defineApi("recall_private_message", RecallPrivateMessageInput, zod_default.object({}), async (ctx, payload) => {
	const uid = await ctx.ntUserApi.getUidByUin(payload.user_id.toString());
	if (!uid) return Failed(-404, "User not found");
	const peer = {
		chatType: 1,
		peerUid: uid,
		guildId: ""
	};
	if (!await ctx.ntFriendApi.isFriend(uid)) {
		if ((await ctx.ntMsgApi.getTempChatInfo(100, uid)).tmpChatInfo.groupCode) peer.chatType = 100;
	}
	const msg = await ctx.ntMsgApi.getMsgsBySeqAndCount(peer, payload.message_seq.toString(), 1, true, true);
	if (msg.msgList.length === 0) return Failed(-404, "Message not found");
	const result = await ctx.ntMsgApi.recallMsg(peer, [msg.msgList[0].msgId]);
	if (result.result !== 0) return Failed(-500, result.errMsg);
	return Ok({});
});
