	async getImageUrl(originImageUrl, md5HexStr) {
		const url = originImageUrl;
		if (url) {
			const parsedUrl = new URL(IMAGE_HTTP_HOST + url);
			const imageAppid = parsedUrl.searchParams.get("appid");
			if (imageAppid && ["1406", "1407"].includes(imageAppid)) {
				let rkey = parsedUrl.searchParams.get("rkey");
				if (rkey) return IMAGE_HTTP_HOST_NT + url;
				const rkeyData = await this.rkeyManager.getRkey();
				rkey = imageAppid === "1406" ? rkeyData.private_rkey : rkeyData.group_rkey;
				return IMAGE_HTTP_HOST_NT + url + rkey;
			} else if (url.startsWith("/offpic_new/")) return `${IMAGE_HTTP_HOST}/gchatpic_new/0/0-0-${md5HexStr.toUpperCase()}/0`;
			else return IMAGE_HTTP_HOST + url;
		} else return `${IMAGE_HTTP_HOST}/gchatpic_new/0/0-0-${md5HexStr.toUpperCase()}/0`;
	}
