//#region src/common/utils/request.ts
var HttpUtil = class HttpUtil {
	static async getCookies(url) {
		const client = url.startsWith("https") ? https : http;
		return new Promise((resolve, reject) => {
			client.get(url, (res) => {
				let cookies = {};
				const handleRedirect = (res) => {
					if (res.statusCode === 301 || res.statusCode === 302) if (res.headers.location) {
						const redirectUrl = new URL(res.headers.location, url);
						HttpUtil.getCookies(redirectUrl.href).then((redirectCookies) => {
							cookies = {
								...cookies,
								...redirectCookies
							};
							resolve(cookies);
						}).catch(reject);
					} else resolve(cookies);
					else resolve(cookies);
				};
				res.on("data", () => {});
				res.on("end", () => {
					handleRedirect(res);
				});
				if (res.headers["set-cookie"]) res.headers["set-cookie"].forEach((cookie) => {
					const parts = cookie.split(";")[0].split("=");
					const key = parts[0];
					const value = parts[1];
					if (key && value && key.length > 0 && value.length > 0) cookies[key] = value;
				});
			}).on("error", (err) => {
				reject(err);
			});
		});
	}
	static async getJson(url, method = "GET", data, headers = {}, isJsonRet = true, isArgJson = true) {
		const option = new URL(url);
		const protocol = url.startsWith("https://") ? https : http;
		const options = {
			hostname: option.hostname,
			port: option.port,
			path: option.href,
			method,
			headers
		};
		return new Promise((resolve, reject) => {
			const req = protocol.request(options, (res) => {
				let responseBody = "";
				res.on("data", (chunk) => {
					responseBody += chunk.toString();
				});
				res.on("end", () => {
					try {
						if (res.statusCode && res.statusCode >= 200 && res.statusCode < 300) if (isJsonRet) resolve(JSON.parse(responseBody));
						else resolve(responseBody);
						else reject(/* @__PURE__ */ new Error(`Unexpected status code: ${res.statusCode}`));
					} catch (parseError) {
						reject(parseError);
					}
				});
			});
			req.on("error", (error) => {
				reject(error);
			});
			if (method === "POST" || method === "PUT" || method === "PATCH") if (isArgJson) req.write(JSON.stringify(data));
			else req.write(data);
			req.end();
		});
	}
	static async getText(url, method = "GET", data, headers = {}) {
		return this.getJson(url, method, data, headers, false, false);
	}
	static async post(url, data = {}, cookies = "", headers = {}) {
		const _headers = {
			"User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) QQ/9.9.23-41857 Chrome/138.0.7204.35 Electron/37.1.0 Safari/537.36 OS/win32,x64,10.0.26100,Windows 11 Pro QQAppId/537320161",
			"Cookie": cookies,
			"Content-Type": "application/json",
			"origin": url.startsWith("https") ? "https://" + new URL(url).hostname : "http://" + new URL(url).hostname,
			...headers
		};
		const response = await fetch(url, {
			method: "POST",
			headers: _headers,
			body: JSON.stringify(data)
		});
		if (!response.ok) throw new Error(`HTTP error! status: ${response.status} statusText: ${response.statusText}`);
		return response;
	}
};
